import os
from openai import api_key
from flask import Flask, request, jsonify

app = Flask(__name__)

# Set OpenAI API key securely (never hardcode in code)
os.environ['OPENAI_API_KEY'] = 'YOUR_OPENAI_API_KEY'

def validate_input(user_message):
    # Validate user input to prevent LLM prompt injection
    if len(user_message) > 2048:
        return "Error: Message too long. Please keep it under 2048 characters."
    return user_message

@app.route('/chat', methods=['POST'])
def chat():
    try:
        user_message = request.json['message']
        validated_message = validate_input(user_message)
        
        # Concatenate system instructions with user input
        prompt = f"User: {validated_message}\nSystem: "
        
        # Use OpenAI API to get model response
        response = api_key.chat(prompt=prompt, model="gpt-3.5-turbo")
        
        return jsonify({'response': response['choices'][0]['message']})
    
    except Exception as e:
        return jsonify({'error': str(e)})

if __name__ == '__main__':
    app.run(debug=True)